```python
class CheckersGame:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.current_player = 'W'
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = 'b'
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 'w'

    def print_board(self):
        # Print the board
        for row in self.board:
            print(' '.join(row or '.'))

    def get_piece(self, x, y):
        return self.board[x][y]

    def move_piece(self, from_x, from_y, to_x, to_y):
        piece = self.get_piece(from_x, from_y)
        if piece is None:
            raise ValueError("No piece at the source position")
        if self.current_player != ('b' if piece == 'w' else 'w'):
            raise ValueError("Not your turn")

        # Simple check for valid move (for now)
        if abs(to_x - from_x) != 1 or abs(to_y - from_y) not in [1, 2]:
            raise ValueError("Invalid move")

        self.board[to_x][to_y] = piece
        self.board[from_x][from_y] = None

    def is_game_over(self):
        # Check if the game is over (simplified check)
        for row in self.board:
            if 'w' in row or 'b' in row:
                return False
        return True
```

