```python
from checkers.game import CheckersGame

def main():
    game = CheckersGame()
    while True:
        game.print_board()
        move = input(f"Player {game.current_player}, enter your move (e.g., 1-2): ")
        try:
            from_x, from_y, to_x, to_y = map(int, move.split('-'))
            game.move_piece(from_x - 1, from_y - 1, to_x - 1, to_y - 1)
        except ValueError as e:
            print(e)
            continue

        if game.is_game_over():
            game.print_board()
            print(f"Player {game.current_player} wins!")
            break
        game.current_player = 'B' if game.current_player == 'W' else 'W'

if __name__ == "__main__":
    main()
```

